const searchHandle = async (e) => {
  const value = e.target.value;
  setSearch(value);

  dispatch({ type: "loading", payload: true });

  try {
    let responseData = await getAllProduct();

    if (responseData && responseData.Products) {
      /*const filtered = responseData.Products.filter((item) =>
       item.pName.toLowerCase().includes(value.toLowerCase()) ||
  item.pCategory.cName.toLowerCase().includes(value.toLowerCase())
      );
const searchValue = value.trim().toLowerCase();

const filtered = responseData.Products.filter(item => {
  const name = item.pName?.toLowerCase() || "";         // safe check for pName
  const category = item.pCategory?.cName?.toLowerCase() || ""; // safe check for category
