};
*/


const searchHandle = async (e) => {
  const value = e.target.value;
  setSearch(value); // update the input

  dispatch({ type: "loading", payload: true }); // show loader

  try {
    let responseData = await getAllProduct(); // get all products

    if (responseData && responseData.Products) {
      const searchValue = value.trim().toLowerCase(); // lowercase & remove spaces

      const filtered = responseData.Products.filter(item => {
        const name = item.pName?.toLowerCase() || "";             // safe check
        const category = item.pCategory?.cName?.toLowerCase() || ""; // safe check
        return name.includes(searchValue) || category.includes(searchValue);
      });

      dispatch({ type: "setProducts", payload: filtered }); // show filtered products
    }
  } catch (error) {
    console.log(error);
  } finally {
    dispatch({ type: "loading", payload: false }); // hide loader
  }
};

const fetchData = async () => {
  try {
    let responseData = await getAllProduct();
    if (responseData && responseData.Products) {
      setPa(responseData.Products); // save full array
      dispatch({ type: "setProducts", payload: responseData.Products }); // show all products
    }
  } catch (error) {
    console.log(error);
  }
};




/*
  const fetchData = async () => {
    dispatch({ type: "loading", payload: true });
    try {
      setTimeout(async () => {
        let responseData = await getAllProduct();
        if (responseData && responseData.Products) {
          setPa(responseData.Products);
          dispatch({ type: "loading", payload: false });
        }
      }, 700);
    } catch (error) {
      console.log(error);
    }
  };

  const closeSearchBar = () => {
    dispatch({ type: "searchDropdown", payload: !data.searchDropdown });
    fetchData();
    dispatch({ type: "setProducts", payload: productArray });
    setSearch("");
  };*/
  const closeSearchBar = () => {
  setSearch(""); // clear input
  dispatch({ type: "setProducts", payload: productArray }); // reset products
  dispatch({ type: "searchDropdown", payload: !data.searchDropdown }); // close dropdown
};


  return (
    <div
      className={`${
        data.searchDropdown ? "" : "hidden"
      } my-4 flex items-center justify-between`}
    >
      <input
        value={search}
        onChange={(e) => searchHandle(e)}
        className="px-4 text-xl py-4 focus:outline-none"
        type="text"
        placeholder="Search Organs..."
      />
      <div onClick={(e) => closeSearchBar()} className="cursor-pointer">
        <svg
          className="w-8 h-8 text-gray-700 hover:bg-gray-200 rounded-full p-1"
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
          xmlns="http://www.w3.org/2000/svg"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth={2}
            d="M6 18L18 6M6 6l12 12"
          />
        </svg>
      </div>
    </div>
  );
};

const ProductCategoryDropdown = (props) => {
  const { data } = useContext(HomeContext); // make sure you have access to data here
  return (
    <Fragment>
      <CategoryList />
      <FilterList />
      <Search />

{/* Product display starts here */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 my-4">
        {data.products && data.products.length > 0 ? (
          data.products.map(item => (
            <div key={item._id} className="product-card border p-2 rounded">
             / <h3>{item.pName || "No Name"}</h3>
              <p>Category: {item.pCategory?.cName || "No Category"}</p>
              <p>{item.pDescription}</p>
              <img 
                src={`${apiURL}/uploads/products/${item.pImages?.[0] || "placeholder.jpg"}`} 
                alt={item.pName} 
                className="w-full h-40 object-cover mt-2"
              />
            </div>
          ))
        ) : (
          <p className="text-center text-gray-500">No products found</p>
        )}
      </div>
      {/* Product display ends here */}


    </Fragment>
  );
};

export default ProductCategoryDropdown;
